import React from 'react';
import { SlideData, SlideType } from '../types';
import { LineChart, Line, ResponsiveContainer, XAxis, Tooltip } from 'recharts';

interface SlideProps {
  data: SlideData;
}

export const Slide: React.FC<SlideProps> = ({ data }) => {
  const renderContent = () => {
    switch (data.type) {
      case SlideType.LIST:
        return (
          <ul className="space-y-4 mt-6">
            {data.content.map((item, idx) => (
              <li key={idx} className="flex items-start text-sm md:text-base leading-relaxed text-gray-800">
                <span className="font-medium">{item}</span>
              </li>
            ))}
          </ul>
        );
      case SlideType.CHART:
        return (
          <div className="h-48 w-full mt-6">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={data.chartData}>
                <XAxis 
                  dataKey="name" 
                  stroke="#9ca3af" 
                  fontSize={12} 
                  tickLine={false} 
                  axisLine={false}
                />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#000', border: 'none', color: '#D4AF37' }}
                  itemStyle={{ color: '#D4AF37' }}
                />
                <Line 
                  type="monotone" 
                  dataKey="value" 
                  stroke="#D4AF37" 
                  strokeWidth={3} 
                  dot={{ fill: '#000', stroke: '#D4AF37', strokeWidth: 2, r: 4 }}
                  activeDot={{ r: 6, fill: '#D4AF37' }}
                />
              </LineChart>
            </ResponsiveContainer>
            <div className="text-center text-xs text-gray-400 mt-2 uppercase tracking-widest">
              Performance Metrics
            </div>
          </div>
        );
      case SlideType.TEXT:
        return (
          <div className="space-y-6 mt-6">
            {data.content.map((item, idx) => (
              <div key={idx} className={idx % 2 === 0 ? "font-bold text-xs tracking-widest text-gold-500 uppercase" : "text-sm text-gray-800 mb-2 border-l-2 border-gold-500 pl-3"}>
                {item}
              </div>
            ))}
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="w-full h-full bg-white p-8 md:p-12 border border-gray-100 shadow-sm flex flex-col relative select-none">
      {/* Decorative Corner */}
      <div className="absolute top-0 right-0 w-16 h-16 overflow-hidden">
        <div className="absolute top-0 right-0 w-4 h-4 bg-black"></div>
        <div className="absolute top-4 right-0 w-[1px] h-12 bg-gray-200"></div>
        <div className="absolute top-0 right-4 w-12 h-[1px] bg-gray-200"></div>
      </div>

      <div className="mb-2">
        <h2 className="font-serif text-2xl md:text-3xl text-black font-semibold tracking-tight">
          {data.title}
        </h2>
        {data.subtitle && (
          <p className="font-sans text-gold-500 text-sm font-medium tracking-wider uppercase mt-2">
            {data.subtitle}
          </p>
        )}
      </div>

      <div className="flex-grow">
        {renderContent()}
      </div>

      <div className="mt-auto pt-6 flex justify-between items-center border-t border-gray-100">
        <span className="text-[10px] text-gray-400 uppercase tracking-widest">Iftiin Confidential</span>
        <span className="text-[10px] font-bold text-black">{String(data.id).padStart(2, '0')}</span>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { ArrowLeft, ArrowRight, Sparkles } from 'lucide-react';
import { Slide } from './Slide';
import { SLIDES } from '../constants';

export const IftiinModule: React.FC = () => {
  const [currentSlideIndex, setCurrentSlideIndex] = useState(0);
  const [isHovered, setIsHovered] = useState(false);

  const nextSlide = useCallback(() => {
    setCurrentSlideIndex((prev) => (prev + 1) % SLIDES.length);
  }, []);

  const prevSlide = useCallback(() => {
    setCurrentSlideIndex((prev) => (prev - 1 + SLIDES.length) % SLIDES.length);
  }, []);

  // Auto-play effect
  useEffect(() => {
    if (isHovered) return;
    const interval = setInterval(nextSlide, 5000);
    return () => clearInterval(interval);
  }, [isHovered, nextSlide]);

  return (
    <section className="w-full max-w-2xl mx-auto my-12 font-sans">

      {/* --- Main Widget Container --- */}
      <div 
        className="relative bg-white shadow-2xl shadow-gray-200/50 border border-gray-100 rounded-sm overflow-hidden group"
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
      >

        {/* Header / Badge */}
        <div className="absolute top-6 left-6 z-20 flex items-center space-x-2">
          <div className="bg-black text-gold-500 text-[10px] font-bold px-3 py-1 uppercase tracking-widest flex items-center gap-2 shadow-lg">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-gold-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-gold-500"></span>
            </span>
            Live Preview
          </div>
        </div>

        {/* Carousel Viewport */}
        <div className="relative w-full aspect-[4/3] bg-gray-50 overflow-hidden">
          <div 
            className="flex transition-transform duration-700 ease-in-out h-full"
            style={{ transform: `translateX(-${currentSlideIndex * 100}%)` }}
          >
            {SLIDES.map((slide) => (
              <div key={slide.id} className="w-full flex-shrink-0 h-full p-4 md:p-8 flex items-center justify-center">
                 {/* Slide Container mimicking a paper document */}
                <div className="w-full h-full shadow-lg transform transition-transform duration-500 hover:scale-[1.01]">
                   <Slide data={slide} />
                </div>
              </div>
            ))}
          </div>

          {/* Navigation Arrows (Visible on Hover) */}
          <button 
            onClick={prevSlide}
            className="absolute left-2 md:left-4 top-1/2 -translate-y-1/2 bg-white/90 hover:bg-black hover:text-gold-500 text-black p-3 rounded-full shadow-lg backdrop-blur-sm transition-all duration-300 opacity-0 group-hover:opacity-100 z-10 border border-gray-100"
            aria-label="Previous slide"
          >
            <ArrowLeft className="w-5 h-5" />
          </button>
          <button 
            onClick={nextSlide}
            className="absolute right-2 md:right-4 top-1/2 -translate-y-1/2 bg-white/90 hover:bg-black hover:text-gold-500 text-black p-3 rounded-full shadow-lg backdrop-blur-sm transition-all duration-300 opacity-0 group-hover:opacity-100 z-10 border border-gray-100"
            aria-label="Next slide"
          >
            <ArrowRight className="w-5 h-5" />
          </button>
        </div>

        {/* Progress Indicators */}
        <div className="bg-white border-t border-gray-100 p-4 flex justify-center items-center gap-3">
            {SLIDES.map((_, idx) => (
              <button
                key={idx}
                onClick={() => setCurrentSlideIndex(idx)}
                className={`transition-all duration-300 rounded-full ${
                  idx === currentSlideIndex 
                    ? 'w-8 h-1 bg-gold-500' 
                    : 'w-1 h-1 bg-gray-300 hover:bg-gray-400'
                }`}
                aria-label={`Go to slide ${idx + 1}`}
              />
            ))}
        </div>
      </div>

      {/* --- Call To Action Section --- */}
      <div className="mt-8 text-center space-y-6 px-4">
        <p className="text-gray-600 font-serif italic text-lg leading-relaxed">
          "Get a glimpse of the first three animated pages. The full blueprint contains actionable data."
        </p>

        <div className="flex flex-col items-center">
          <button className="group relative w-full md:w-auto min-w-[300px] bg-black text-white px-8 py-5 overflow-hidden transition-all duration-300 hover:shadow-2xl hover:shadow-gold-500/20 active:scale-95">
             {/* Gold shine effect overlay */}
            <div className="absolute inset-0 w-full h-full bg-gradient-to-r from-transparent via-gold-500/10 to-transparent -translate-x-full group-hover:animate-[shimmer_1.5s_infinite]"></div>

            <div className="relative flex items-center justify-center gap-3">
              <span className="font-sans font-bold tracking-[0.2em] text-gold-500">BUY NOW & INSTANT DOWNLOAD</span>
              <Sparkles className="w-4 h-4 text-gold-500 transition-transform duration-300 group-hover:rotate-12" />
            </div>
          </button>

          <p className="mt-4 text-[10px] text-gray-400 uppercase tracking-widest">
            Secure Payment • Instant Access • Lifetime Updates
          </p>
        </div>
      </div>
    </section>
  );
};

export enum SlideType {
  TEXT = 'TEXT',
  CHART = 'CHART',
  LIST = 'LIST',
  QUOTE = 'QUOTE',
  STATS = 'STATS',
  TIMELINE = 'TIMELINE'
}

export interface SlideData {
  id: number;
