              <div key={idx} className={idx % 2 === 0 ? "font-bold text-xs tracking-widest text-gold-500 uppercase" : "text-sm text-gray-800 mb-2 border-l-2 border-gold-500 pl-3"}>
                {item}
              </div>
            ))}
          </div>
        );
      case SlideType.STATS:
        return (
          <div className="grid grid-cols-2 gap-4 mt-6">
