                  ) : (
                    // LOCKED STATE
                    <div className="relative mt-4">
                       <p className="text-gray-600 font-serif leading-relaxed blur-[4px] select-none">
                         {post.excerpt} The rest of this content is hidden. Join the community to unlock full analysis, data sets, and direct access to our consulting team.
                         We reveal the specific numbers that drive 80% of the results.
                       </p>

                       {/* Overlay Container */}
                       <div className="absolute inset-0 flex items-center justify-center bg-white/30">
