  const [membershipState, setMembershipState] = useState<'IDLE' | 'INPUT' | 'SUCCESS'>('IDLE');
  const [memberEmail, setMemberEmail] = useState("");

  const handleUnlockStart = (postId: number) => {
    setUnlockingPostId(postId);
    setPostEmail("");
  };

  const handleUnlockSubmit = (e: React.FormEvent, postId: number) => {
    e.preventDefault();
    if (!postEmail) return;

    // Simulate API call
    setTimeout(() => {
      setUnlockedPostIds(prev => [...prev, postId]);
      setUnlockingPostId(null);
      setPostEmail("");
    }, 600);
  };

  const handleMemberSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!memberEmail) return;

    // Simulate API call
    setTimeout(() => {
      setMembershipState('SUCCESS');
    }, 600);
  };

  return (
    <div className="max-w-7xl mx-auto animate-in fade-in duration-500">

