        </div>

        {/* Right Column: Sidebar / Membership */}
        <aside className="lg:col-span-4 space-y-12">

          {/* Membership Widget - Sharp, Black, Gold */}
          <div className="bg-black text-white p-8 relative overflow-hidden group">
            {/* Gold Geometric Decor */}
            <div className="absolute top-0 right-0 w-full h-1 bg-gold-500"></div>
            <div className="absolute bottom-0 left-0 w-full h-1 bg-white/10"></div>

            <div className="relative z-10">
