                       We reveal the specific numbers that drive 80% of the results.
                     </p>

                     {/* Overlay Container */}
                     <div className="absolute inset-0 flex items-center justify-center bg-white/40 backdrop-blur-[1px]">
                        {isUnlocking ? (
                          // INPUT FORM - Sharp
                          <form 
                            onSubmit={(e) => handleUnlockSubmit(e, post.id)}
                            className="bg-white p-6 shadow-2xl border border-black flex flex-col gap-4 w-full max-w-sm animate-in zoom-in-95 duration-200"
                          >
                            <div className="text-center mb-2">
                              <span className="text-[10px] font-bold uppercase tracking-widest text-gold-600 block mb-1">{t.journal.locked}</span>
