                                value={postEmail}
                                onChange={(e) => setPostEmail(e.target.value)}
                                autoFocus
                                required
                              />
                              <button 
                                type="submit"
                                className="bg-black text-white px-4 py-3 text-[10px] font-bold uppercase tracking-widest hover:bg-gold-500 hover:text-black transition-colors w-full"
