                        <Heart className="w-4 h-4" />
                        <span className="text-[10px] font-bold uppercase tracking-wider">{post.likes}</span>
                      </button>
                      <button className="flex items-center gap-2 text-gray-400 hover:text-black transition-colors">
                        <MessageSquare className="w-4 h-4" />
                        <span className="text-[10px] font-bold uppercase tracking-wider">{post.comments}</span>
                      </button>
                   </div>
                   <button className="text-gray-400 hover:text-gold-500 transition-colors flex items-center gap-2 text-[10px] font-bold uppercase tracking-wider">
                     <Share2 className="w-3 h-3" />
                   </button>
                </div>
              </div>
            );
          })}
        </div>

        {/* Right Column: Sidebar / Membership */}
        <aside className="lg:col-span-4 space-y-12">

