                       >
                         {t.journal.joinNow}
                       </button>
                     </div>
                   </div>
                </form>
              )}

              {membershipState === 'SUCCESS' && (
                 <button className="w-full mt-4 text-white border border-white/20 py-3 text-[10px] font-bold uppercase tracking-widest hover:border-gold-500 hover:text-gold-500 transition-colors flex items-center justify-center gap-2">
