                {t.contact.successDesc}
              </p>
              <button 
                onClick={() => setFormState('IDLE')}
                className="text-[10px] font-bold uppercase tracking-widest text-black border-b border-black pb-1 hover:text-gold-600 hover:border-gold-600 transition-colors"
