import React, { useState } from 'react';
import { Lock, Heart, MessageSquare, Share2, Unlock, Star, ArrowRight, Check, ChevronRight } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { getPosts } from '../constants';

interface JournalPageProps {
  onOpenPost: (id: number) => void;
  unlockedPostIds: number[];
  onUnlockPost: (id: number) => void;
}

export const JournalPage: React.FC<JournalPageProps> = ({ onOpenPost, unlockedPostIds, onUnlockPost }) => {
  const { t, language } = useLanguage();
  const posts = getPosts(language);

  // Local state for sidebar input only
  const [unlockingPostId, setUnlockingPostId] = useState<number | null>(null);
  const [postEmail, setPostEmail] = useState("");
  const [unlockError, setUnlockError] = useState<string | null>(null);

  const [membershipState, setMembershipState] = useState<'IDLE' | 'INPUT' | 'SUCCESS'>('IDLE');
  const [memberEmail, setMemberEmail] = useState("");
  const [memberError, setMemberError] = useState<string | null>(null);

  const validateEmail = (email: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const handleUnlockStart = (postId: number) => {
    setUnlockingPostId(postId);
    setPostEmail("");
    setUnlockError(null);
  };

  const handleUnlockSubmit = (e: React.FormEvent, postId: number) => {
    e.preventDefault();
    setUnlockError(null);

    if (!postEmail) return;

    if (!validateEmail(postEmail)) {
      setUnlockError(language === 'DE' ? "Ungültige E-Mail-Adresse" : "Invalid email address");
      return;
    }

    // TODO: Connect to backend API
    console.log(`[Journal] Unlocking Post ID ${postId} with email:`, postEmail);

    // Simulate API call
    setTimeout(() => {
      onUnlockPost(postId); // Update global unlocked state
      setUnlockingPostId(null);
      setPostEmail("");
      onOpenPost(postId); // Navigate to detail page immediately
    }, 600);
  };

  const handleMemberSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setMemberError(null);

    if (!memberEmail) return;

    if (!validateEmail(memberEmail)) {
      setMemberError(language === 'DE' ? "Ungültige E-Mail-Adresse" : "Invalid email address");
      return;
    }

    // TODO: Connect to backend API
    console.log(`[Membership] New signup request:`, memberEmail);

    // Simulate API call
    setTimeout(() => {
      setMembershipState('SUCCESS');
    }, 600);
  };

  const handlePostTitleClick = (post: any, isUnlocked: boolean) => {
    if (!post.isLocked || isUnlocked) {
      onOpenPost(post.id);
    } else {
      handleUnlockStart(post.id);
    }
  };

  return (
    <div className="max-w-7xl mx-auto animate-in fade-in duration-500">

      {/* Page Header - Briefing Style */}
      <div className="mb-16 border-b border-black pb-8">
        <h2 className="font-serif text-5xl font-bold mb-4">{t.journal.title}</h2>
        <div className="flex items-center gap-4 text-xs font-bold uppercase tracking-widest text-gray-500">
          <span>{t.journal.subtitle[0]}</span>
          <span className="text-gold-500">•</span>
          <span>{t.journal.subtitle[1]}</span>
          <span className="text-gold-500">•</span>
          <span>{t.journal.subtitle[2]}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Left Column: The Feed */}
        <div className="lg:col-span-8 space-y-12">
          {posts.map((post) => {
            const isUnlocked = !post.isLocked || unlockedPostIds.includes(post.id);
            const isUnlocking = unlockingPostId === post.id;

            return (
              <div key={post.id} className="group border-b border-gray-200 pb-12 last:border-0">

                {/* Meta Row */}
                <div className="flex items-center gap-4 mb-4">
                  <span className="text-[10px] font-bold text-gold-600 uppercase tracking-widest border border-gold-200 px-2 py-1 bg-gold-50/50">
                    {post.date}
                  </span>
                  {post.isLocked && !isUnlocked && (
                    <span className="flex items-center gap-1.5 text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                      <Lock className="w-3 h-3" /> {post.tier} Only
                    </span>
                  )}
                  {isUnlocked && post.isLocked && (
                    <span className="flex items-center gap-1.5 text-[10px] font-bold text-green-600 uppercase tracking-widest">
                      <Unlock className="w-3 h-3" /> Access Granted
                    </span>
                  )}
                </div>

                <h3 
                  onClick={() => handlePostTitleClick(post, isUnlocked)}
                  className="font-serif text-3xl font-medium mb-4 leading-tight group-hover:text-gold-600 transition-colors cursor-pointer"
                >
                  {post.title}
                </h3>

                {isUnlocked ? (
                  // UNLOCKED / OPEN STATE
                  <div className="animate-in fade-in duration-700">
                    <p className="text-gray-600 font-serif text-lg leading-8 mb-6">
                      {post.excerpt}
                    </p>
                    <button 
                      onClick={() => onOpenPost(post.id)}
                      className="text-xs font-bold uppercase tracking-widest border-b border-black pb-1 hover:text-gold-600 hover:border-gold-600 transition-colors"
                    >
                      {t.journal.readMore}
                    </button>
                  </div>
