                                value={postEmail}
                                onChange={(e) => {
                                  setPostEmail(e.target.value);
                                  if (unlockError) setUnlockError(null);
                                }}
                                autoFocus
                                required
                              />
                              {unlockError && (
                                <span className="text-red-500 text-[9px] font-bold uppercase tracking-widest">{unlockError}</span>
                              )}
                              <button 
                                type="submit"
                                className="bg-black text-white px-4 py-3 text-[10px] font-bold uppercase tracking-widest hover:bg-gold-500 hover:text-black transition-colors w-full"
