                              {t.journal.return}
                            </button>
                          </form>
                        ) : (
                          // UNLOCK BUTTON - Sharp
                          <button 
                            onClick={() => handleUnlockStart(post.id)}
                            className="bg-white border border-black text-black px-8 py-4 text-xs font-bold uppercase tracking-widest flex items-center gap-3 hover:bg-black hover:text-white transition-all duration-300 shadow-xl"
                          >
                            <Unlock className="w-4 h-4" /> {t.journal.unlock}
