                {membershipState === 'SUCCESS' ? <Check className="w-5 h-5" /> : <Star className="w-5 h-5" />}
              </div>

              <h3 className="font-serif text-2xl font-bold mb-4 text-white">
                {membershipState === 'SUCCESS' ? t.journal.successTitle : t.journal.joinTitle}
              </h3>

              <p className="text-gray-400 text-sm leading-relaxed mb-8">
                {membershipState === 'SUCCESS' 
                  ? t.journal.successDesc 
                  : t.journal.joinDesc}
              </p>

              {membershipState === 'IDLE' && (
                <>
                  <button 
                    onClick={() => setMembershipState('INPUT')}
                    className="w-full bg-white text-black py-4 text-[10px] font-bold uppercase tracking-[0.2em] hover:bg-gold-500 transition-colors"
                  >
                    {t.journal.activate}
                  </button>
                  <div className="flex items-center justify-between mt-4 text-[9px] text-gray-600 uppercase tracking-widest">
                    <span>Limited Access</span>
                    <span>No Credit Card</span>
                  </div>
                </>
              )}

              {membershipState === 'INPUT' && (
                <form onSubmit={handleMemberSubmit} className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                   <div className="flex flex-col gap-4">
                     <div>
                        <label className="text-[10px] font-bold uppercase tracking-widest text-gray-500 mb-2 block">{t.contact.email}</label>
                        <input 
                          type="email" 
                          placeholder={t.journal.inputPlaceholder}
                          className={`w-full bg-white/5 border text-white placeholder-gray-600 px-4 py-3 text-xs focus:outline-none focus:border-gold-500 transition-colors rounded-none ${memberError ? 'border-red-500' : 'border-white/20'}`}
                          value={memberEmail}
                          onChange={(e) => {
                            setMemberEmail(e.target.value);
                            if (memberError) setMemberError(null);
                          }}
                          autoFocus
                          required
                        />
                        {memberError && (
                          <span className="text-red-500 text-[9px] font-bold uppercase tracking-widest mt-1 block">{memberError}</span>
                        )}
                     </div>
                     <div className="flex gap-4">
                       <button 
                         type="button"
                         onClick={() => setMembershipState('IDLE')}
                         className="flex-1 bg-transparent border border-white/20 text-white py-3 text-[10px] font-bold uppercase tracking-widest hover:bg-white/10 transition-colors"
                       >
                         {t.journal.back}
                       </button>
                       <button 
                         type="submit"
                         className="flex-[2] bg-gold-500 text-black py-3 text-[10px] font-bold uppercase tracking-widest hover:bg-white transition-colors"
                       >
                         {t.journal.joinNow}
                       </button>
                     </div>
                   </div>
                </form>
              )}

              {membershipState === 'SUCCESS' && (
                 <button className="w-full mt-4 text-white border border-white/20 py-3 text-[10px] font-bold uppercase tracking-widest hover:border-gold-500 hover:text-gold-500 transition-colors flex items-center justify-center gap-2">
                   {t.journal.launch} <ChevronRight className="w-3 h-3" />
