            <div className="flex flex-col gap-4">
              <span className="text-gold-500 mb-2">{t.footer.legal}</span>
              <button onClick={() => navigate('PRIVACY')} className="text-left hover:underline">{t.footer.privacy}</button>
              <button onClick={() => navigate('TERMS')} className="text-left hover:underline">{t.footer.terms}</button>
            </div>
          </div>
        </div>
        <div className="max-w-7xl mx-auto mt-20 pt-8 border-t border-gray-100 flex justify-between items-center text-[10px] text-gray-400 uppercase tracking-widest">
          <span>{t.footer.rights}</span>
        </div>
      </footer>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <LanguageProvider>
      <AppContent />
    </LanguageProvider>
  );
}

