import React from 'react';
import { useLanguage } from '../contexts/LanguageContext';
import { FileText } from 'lucide-react';

interface LegalPageProps {
  type: 'PRIVACY' | 'TERMS' | 'IMPRESSUM';
}

export const LegalPage: React.FC<LegalPageProps> = ({ type }) => {
  const { t } = useLanguage();

  let sections;
  let title;

  switch (type) {
    case 'PRIVACY':
      sections = t.legal.privacySections;
      title = t.legal.privacyTitle;
      break;
    case 'TERMS':
      sections = t.legal.termsSections;
      title = t.legal.termsTitle;
      break;
    case 'IMPRESSUM':
      sections = t.legal.impressumSections;
      title = t.legal.impressumTitle;
      break;
    default:
      sections = [];
      title = '';
  }

  const scrollToSection = (index: number) => {
    const element = document.getElementById(`legal-section-${index}`);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  };

  return (
    <div className="animate-in fade-in duration-500 w-full font-sans">

      {/* Header Section */}
      <div className="bg-gray-50 border-b border-gray-200 py-16 md:py-24">
        <div className="max-w-7xl mx-auto px-6 md:px-12">
           <div className="max-w-4xl">
              <div className="flex items-center gap-3 mb-6 text-gold-600">
                <FileText className="w-5 h-5" />
                <span className="font-bold text-[10px] tracking-[0.25em] uppercase">{t.legal.label}</span>
              </div>
              <h1 className="font-serif text-4xl md:text-6xl font-medium leading-[1.1] mb-6 text-black">
                {title}
              </h1>
              <div className="flex items-center gap-4 text-xs font-bold uppercase tracking-widest text-gray-500">
                <span>{t.legal.updated}</span>
                <span className="w-1 h-1 bg-gray-400 rounded-full"></span>
                <span>Iftiin Flow</span>
              </div>
           </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 md:px-12 py-16">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-24">

          {/* Sidebar / Table of Contents (Desktop Only) */}
          <aside className="lg:col-span-4 hidden lg:block">
            <div className="sticky top-32">
              <h3 className="font-serif text-lg font-bold mb-6 border-b border-black pb-4">Inhalt</h3>
              <nav className="flex flex-col gap-3">
                {sections && sections.map((section, idx) => (
                  <button 
                    key={idx}
                    onClick={() => scrollToSection(idx)}
                    className="text-left text-xs font-bold uppercase tracking-wider text-gray-400 hover:text-black transition-colors py-2 flex items-start gap-3 group"
                  >
                    <span className="text-gold-500 opacity-0 -translate-x-2 group-hover:translate-x-0 group-hover:opacity-100 transition-all duration-300">→</span>
                    <span className="line-clamp-2 leading-relaxed">{section.title}</span>
                  </button>
                ))}
              </nav>
            </div>
          </aside>

          {/* Main Content */}
          <div className="lg:col-span-8">
            <div className="prose prose-lg max-w-none prose-headings:font-serif prose-headings:font-medium prose-p:font-sans prose-p:text-gray-600 prose-p:leading-8 prose-li:text-gray-600">

              <div className="text-sm font-bold uppercase tracking-widest text-gray-500 mb-12 border-l-2 border-gold-500 pl-6 py-4 bg-gray-50">
                {t.legal.agreement}
              </div>

              {sections && sections.map((section, idx) => (
                <div key={idx} id={`legal-section-${idx}`} className="scroll-mt-32 mb-16 border-b border-gray-100 pb-12 last:border-0 last:pb-0 last:mb-0">
                  <h3 className="text-2xl text-black mb-6">{section.title}</h3>
                  <div className="whitespace-pre-line text-base text-gray-700 leading-relaxed">
                    {section.content}
                  </div>
                </div>
              ))}

              {(!sections || sections.length === 0) && (
                <p className="text-gray-500 italic">Content is currently being updated.</p>
              )}
            </div>

            {/* Footer Note */}
             <div className="mt-16 p-8 bg-gray-50 border border-gray-200">
                <p className="text-xs text-gray-500 text-center leading-relaxed">
                  Bei Fragen zu diesem Dokument kontaktieren Sie uns bitte unter <a href="mailto:contact@iftiin-flow.com" className="text-black font-bold hover:text-gold-500 underline decoration-gray-300 underline-offset-4">contact@iftiin-flow.com</a>.
                </p>
             </div>
          </div>

        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ArticlePage } from './components/ArticlePage';
import { JournalPage } from './components/JournalPage';
import { JournalPostPage } from './components/JournalPostPage';
import { BlueprintsPage } from './components/BlueprintsPage';
import { ContactPage } from './components/ContactPage';
import { LegalPage } from './components/LegalPage';
import { GeometricHome } from './components/GeometricHome';
import { ManifestoPage } from './components/ManifestoPage';
import { ServicesPage } from './components/ServicesPage';
import { Menu, Search, User, X } from 'lucide-react';
import { LanguageProvider, useLanguage } from './contexts/LanguageContext';

type View = 'HOME' | 'ARTICLE' | 'JOURNAL' | 'JOURNAL_POST' | 'BLUEPRINTS' | 'ABOUT' | 'CONTACT' | 'PRIVACY' | 'TERMS' | 'MANIFESTO' | 'SERVICES' | 'IMPRESSUM';

const AppContent: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('HOME');
  const [selectedPostId, setSelectedPostId] = useState<number | null>(null);
  const [unlockedPostIds, setUnlockedPostIds] = useState<number[]>([]);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const { language, setLanguage, t } = useLanguage();

  const navigate = (view: View) => {
    setCurrentView(view);
    setIsMobileMenuOpen(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleOpenPost = (postId: number) => {
    setSelectedPostId(postId);
    navigate('JOURNAL_POST');
  };

  const handleUnlockPost = (postId: number) => {
    setUnlockedPostIds(prev => [...prev, postId]);
  };

  const handleLogoClick = () => {
    navigate('HOME');
  };

  return (
    <div className="min-h-screen bg-transparent text-black selection:bg-gold-500 selection:text-white flex flex-col font-sans">
      {/* Top Utility Bar (Consultancy Style) */}
      <div className="bg-white border-b border-gray-100 text-black px-6 md:px-12 py-3 flex justify-between items-center text-[10px] tracking-[0.2em] uppercase font-medium">
        <span className="text-gray-500 font-bold">{t.nav.headerSubtitle}</span>
        <div className="flex gap-6">
           <button 
             onClick={() => navigate('MANIFESTO')}
             className="hover:text-gold-600 cursor-pointer transition-colors uppercase"
           >
             {t.nav.manifesto}
           </button>
           <button 
             onClick={() => navigate('SERVICES')}
             className={`hover:text-gold-600 cursor-pointer transition-colors uppercase ${currentView === 'SERVICES' ? 'text-black font-bold' : ''}`}
           >
             {t.nav.services}
           </button>
           <button 
            onClick={() => setLanguage(language === 'EN' ? 'DE' : 'EN')}
            className="hover:text-gold-600 transition-colors font-bold"
          >
            {language === 'EN' ? 'DE' : 'EN'}
          </button>
        </div>
      </div>

      {/* Navigation */}
      <nav className={`py-6 px-6 md:px-12 sticky top-0 z-50 transition-colors duration-300 ${currentView === 'HOME' ? 'bg-white/80 backdrop-blur-md' : 'bg-white/95 border-b border-black backdrop-blur-md'}`}>
        <div className="flex justify-between items-center">
          <div className="flex flex-col md:flex-row items-center gap-2 md:gap-12">
             {/* Logo - Restored to IFTIIN */}
             <h1 className="font-serif text-3xl font-bold tracking-tight cursor-pointer leading-none group" onClick={handleLogoClick}>
               IFTIIN<span className="text-gold-500 group-hover:text-black transition-colors">.</span>
             </h1>

             {/* Desktop Links */}
             <div className="hidden md:flex gap-8 text-[11px] font-bold tracking-[0.15em] uppercase text-gray-500">
               <button 
                onClick={() => navigate('ARTICLE')} 
                className={`hover:text-black transition-colors ${currentView === 'ARTICLE' ? 'text-black border-b border-black pb-0.5' : ''}`}
               >
                 AI Literacy
               </button>
               <button 
                onClick={() => navigate('JOURNAL')} 
                className={`hover:text-black transition-colors ${currentView === 'JOURNAL' || currentView === 'JOURNAL_POST' ? 'text-black border-b border-black pb-0.5' : ''}`}
               >
                 {t.nav.journal}
               </button>
               <button 
                onClick={() => navigate('BLUEPRINTS')}
                className={`hover:text-black transition-colors ${currentView === 'BLUEPRINTS' ? 'text-black border-b border-black pb-0.5' : ''}`}
               >
                 {t.nav.blueprints}
               </button>
               <button 
                onClick={() => navigate('SERVICES')}
                className={`hover:text-black transition-colors ${currentView === 'SERVICES' ? 'text-black border-b border-black pb-0.5' : ''}`}
               >
                 {t.nav.services}
               </button>
               <button 
                onClick={() => navigate('ABOUT')}
                className={`hover:text-black transition-colors ${currentView === 'ABOUT' ? 'text-black border-b border-black pb-0.5' : ''}`}
               >
                 {t.nav.about}
               </button>
             </div>
          </div>

          <div className="flex items-center gap-6 text-black">
            <button 
              onClick={() => navigate('CONTACT')}
