              {isMobileMenuOpen ? (
                <X className="w-6 h-6 text-black hover:text-gold-500 transition-colors" />
              ) : (
                <Menu className="w-6 h-6 hover:text-gold-500 transition-colors" />
              )}
            </button>
          </div>
        </div>

        {/* Mobile Menu */}
        {isMobileMenuOpen && (
