             <button onClick={() => navigate('BLUEPRINTS')} className="text-left text-sm font-bold tracking-widest uppercase text-black hover:text-gold-500 transition-colors">{t.nav.blueprints}</button>
             <button onClick={() => navigate('SERVICES')} className="text-left text-sm font-bold tracking-widest uppercase text-black hover:text-gold-500 transition-colors">{t.nav.services}</button>
             <button onClick={() => navigate('ABOUT')} className="text-left text-sm font-bold tracking-widest uppercase text-black hover:text-gold-500 transition-colors">{t.nav.about}</button>
             <button onClick={() => navigate('CONTACT')} className="text-left text-sm font-bold tracking-widest uppercase text-black hover:text-gold-500 transition-colors">{t.nav.contact}</button>
          </div>
        )}
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow w-full">
        {currentView === 'HOME' && <GeometricHome onNavigate={navigate} />}

        {/* Wrap other pages in container */}
        <div className={`${currentView !== 'HOME' ? 'max-w-7xl mx-auto px-6 py-16 md:py-24' : ''}`}>
           {currentView === 'ARTICLE' && <ArticlePage />}
           {currentView === 'JOURNAL' && (
             <JournalPage 
               onOpenPost={handleOpenPost} 
               unlockedPostIds={unlockedPostIds}
               onUnlockPost={handleUnlockPost}
             />
           )}
           {currentView === 'JOURNAL_POST' && selectedPostId && (
             <JournalPostPage 
               postId={selectedPostId} 
               onBack={() => navigate('JOURNAL')} 
             />
           )}
           {currentView === 'BLUEPRINTS' && <BlueprintsPage />}
           {currentView === 'CONTACT' && <ContactPage />}
           {currentView === 'PRIVACY' && <LegalPage type="PRIVACY" />}
           {currentView === 'TERMS' && <LegalPage type="TERMS" />}
           {currentView === 'IMPRESSUM' && <LegalPage type="IMPRESSUM" />}
           {currentView === 'MANIFESTO' && <ManifestoPage />}
           {currentView === 'SERVICES' && <ServicesPage onNavigateContact={() => navigate('CONTACT')} />}

           {currentView === 'ABOUT' && (
              <div className="flex flex-col items-center justify-center min-h-[40vh] text-center animate-in fade-in duration-500 border-t border-b border-gray-100 py-20">
                <span className="text-gold-500 font-serif text-6xl mb-6">{t.about.title}</span>
                <p className="text-gray-900 font-serif text-xl italic max-w-2xl mx-auto mb-8 leading-relaxed">
                  {t.about.mission}
                </p>
                <p className="text-gray-500 max-w-2xl mx-auto leading-relaxed">
                  {t.about.subMission}
                </p>
                <div className="w-12 h-[1px] bg-black my-8"></div>
                <button onClick={() => navigate('ARTICLE')} className="text-[10px] font-bold uppercase tracking-widest hover:text-gold-600">
                  {t.about.returnBtn}
                </button>
              </div>
           )}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-gray-200 text-black py-20 px-6 mt-auto">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-start gap-12">
          <div className="max-w-xs">
            <h3 className="font-serif text-2xl font-bold mb-4">IFTIIN<span className="text-gold-500">.</span></h3>
            <p className="text-gray-500 text-sm leading-relaxed">
              {t.about.mission}
            </p>
          </div>
          <div className="grid grid-cols-2 md:grid-cols-3 gap-12 md:gap-24 text-[10px] font-bold uppercase tracking-widest">
            <div className="flex flex-col gap-4">
              <span className="text-gold-500 mb-2">{t.footer.platform}</span>
              <button onClick={() => navigate('BLUEPRINTS')} className="text-left hover:underline">{t.nav.blueprints}</button>
              <button onClick={() => navigate('SERVICES')} className="text-left hover:underline">{t.nav.services}</button>
            </div>
            <div className="flex flex-col gap-4">
              <span className="text-gold-500 mb-2">{t.footer.company}</span>
              <button onClick={() => navigate('ABOUT')} className="text-left hover:underline">{t.nav.about}</button>
              <button onClick={() => navigate('CONTACT')} className="text-left hover:underline">{t.nav.contact}</button>
            </div>
            <div className="flex flex-col gap-4">
              <span className="text-gold-500 mb-2">{t.footer.legal}</span>
              <button onClick={() => navigate('PRIVACY')} className="text-left hover:underline">{t.footer.privacy}</button>
              <button onClick={() => navigate('TERMS')} className="text-left hover:underline">{t.footer.terms}</button>
              <button onClick={() => navigate('IMPRESSUM')} className="text-left hover:underline">{t.footer.impressum}</button>
            </div>
          </div>
        </div>
        <div className="max-w-7xl mx-auto mt-20 pt-8 border-t border-gray-100 flex justify-between items-center text-[10px] text-gray-400 uppercase tracking-widest">
          <span>{t.footer.rights}</span>
        </div>
      </footer>
    </div>
  );
};

