    switch(type) {
      case 'ZAP': return <Zap className="w-6 h-6 text-white" />;
      case 'ZAP_GOLD': return <Zap className="w-6 h-6 text-gold-500" />;
      case 'BOOK': return <BookOpen className="w-6 h-6 text-white" />;
      case 'TOOL': return <PenTool className="w-6 h-6 text-white" />;
      case 'GLOBE': return <Globe className="w-6 h-6 text-white" />;
      default: return <Zap className="w-6 h-6 text-white" />;
    }
  };

  return (
    <div className="max-w-7xl mx-auto animate-in fade-in duration-500">

      {/* Header Section (Consultancy Style) */}
      <div className="mb-16 border-b border-black pb-8">
