              {t.blueprints.title}
            </h2>
            <p className="text-gray-600 font-serif text-lg leading-relaxed max-w-xl">
              {t.blueprints.desc}
            </p>
          </div>
          <div className="mb-2 hidden md:block">
            <span className="text-[10px] font-bold uppercase tracking-widest text-gray-400">Displaying {filteredProducts.length} Assets</span>
