        </div>
      </div>

      {/* Filter Tabs (Minimalist) */}
      <div className="flex flex-wrap gap-x-8 gap-y-4 mb-16">
        {categories.map((cat) => (
          <button
            key={cat}
            onClick={() => setFilter(cat)}
            className={`text-[11px] font-bold uppercase tracking-[0.15em] py-2 transition-all duration-300 relative group ${
              filter === cat 
                ? 'text-black' 
                : 'text-gray-400 hover:text-black'
            }`}
          >
            {cat}
            <span className={`absolute bottom-0 left-0 h-[2px] bg-gold-500 transition-all duration-300 ${filter === cat ? 'w-full' : 'w-0 group-hover:w-full'}`}></span>
          </button>
        ))}
      </div>

      {/* Grid Layout - Sharp, Corporate Style */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-x-6 gap-y-12 mb-20">
        {filteredProducts.map((product) => (
          <div key={product.id} className="group flex flex-col h-full bg-white transition-all duration-300 border border-gray-200">

            {/* Visual Area with Image */}
            <div className="relative h-56 bg-gray-100 overflow-hidden">
               {/* Product Image */}
               <img 
                 src={(product as any).imageUrl} 
                 alt={product.title}
                 className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110 grayscale group-hover:grayscale-0"
               />

               {/* Dark Overlay */}
               <div className="absolute inset-0 bg-black/40 group-hover:bg-black/20 transition-colors duration-300"></div>

               {/* Icon Badge */}
               <div className="absolute top-4 left-4 z-10 p-2 bg-black/80 backdrop-blur-sm border border-white/10">
                 {getIcon(product.iconType)}
               </div>

               {/* Gold Accent Top Line */}
               <div className="absolute top-0 left-0 w-full h-[4px] bg-gold-500"></div>

               {/* Hover Action Button */}
               <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300 z-20">
                 <button 
                   onClick={() => openPayhipPlaceholder(product)}
                   className="bg-white text-black px-6 py-3 text-[10px] font-bold uppercase tracking-widest shadow-2xl flex items-center gap-2 hover:bg-gold-500 transition-colors"
                 >
                   {t.blueprints.instantAccess} <ChevronRight className="w-3 h-3" />
                 </button>
               </div>
            </div>

            {/* Content Area */}
            <div className="flex flex-col flex-grow p-6 bg-white">
              <div className="mb-4">
                <span className="text-[9px] text-gold-600 font-bold uppercase tracking-[0.2em] block mb-2">{product.category}</span>
                <h3 className="font-serif text-xl font-bold text-black leading-tight group-hover:text-gold-600 transition-colors">
                  {product.title}
                </h3>
              </div>

              <p className="text-gray-500 text-xs leading-6 mb-6 line-clamp-3">
                {typeof product.description === 'function' ? product.description(language) : product.description}
              </p>

              <div className="mt-auto flex items-center justify-between pt-4 border-t border-gray-100">
                <span className="font-serif font-bold text-xl text-black">${product.price}</span>
                <button 
                  onClick={() => openPayhipPlaceholder(product)}
                  className="text-[10px] font-bold uppercase tracking-widest text-black hover:text-gold-600 transition-colors flex items-center gap-2 border-b border-transparent hover:border-gold-600 pb-1"
                >
                  {t.blueprints.buyNow}
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Trust Elements - Minimalist Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 border-t border-black">
        <div className="py-12 pr-8 border-b md:border-b-0 border-gray-200 md:border-r">
           <h4 className="font-serif font-bold text-xl mb-3 flex items-center gap-3">
             <Download className="w-5 h-5 text-gold-500" /> {t.blueprints.trust.t1.title}
           </h4>
           <p className="text-sm text-gray-500 leading-relaxed">
             {t.blueprints.trust.t1.desc}
           </p>
        </div>
        <div className="py-12 md:px-8 border-b md:border-b-0 border-gray-200 md:border-r">
           <h4 className="font-serif font-bold text-xl mb-3 flex items-center gap-3">
             <Zap className="w-5 h-5 text-gold-500" /> {t.blueprints.trust.t2.title}
           </h4>
           <p className="text-sm text-gray-500 leading-relaxed">
             {t.blueprints.trust.t2.desc}
           </p>
        </div>
        <div className="py-12 md:pl-8">
           <h4 className="font-serif font-bold text-xl mb-3 flex items-center gap-3">
             <ShoppingBag className="w-5 h-5 text-gold-500" /> {t.blueprints.trust.t3.title}
           </h4>
           <p className="text-sm text-gray-500 leading-relaxed">
             {t.blueprints.trust.t3.desc}
           </p>
        </div>
      </div>
    </div>
  );
};

